import { memo, useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { ArrowRight, Landmark, MapPin } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { supabase } from "@/integrations/supabase/client";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useUserGeolocation } from "@/hooks/useUserGeolocation";

interface LandmarkItem {
  id: string;
  name: string;
  name_en: string | null;
  name_pt: string | null;
  image_url: string | null;
  city: string | null;
  country: string | null;
  lat: number;
  lng: number;
  distance?: number;
}

function haversineKm(lat1: number, lng1: number, lat2: number, lng2: number) {
  const R = 6371;
  const dLat = ((lat2 - lat1) * Math.PI) / 180;
  const dLng = ((lng2 - lng1) * Math.PI) / 180;
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos((lat1 * Math.PI) / 180) * Math.cos((lat2 * Math.PI) / 180) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

const useResponsiveCount = () => {
  const [count, setCount] = useState(4);
  useEffect(() => {
    const update = () => {
      const w = window.innerWidth;
      setCount(w < 640 ? 2 : w < 1024 ? 3 : 4);
    };
    update();
    window.addEventListener("resize", update);
    return () => window.removeEventListener("resize", update);
  }, []);
  return count;
};

const LandmarkCard = memo(({ item, userLat, userLng }: { item: LandmarkItem; userLat: number | null; userLng: number | null }) => {
  const navigate = useNavigate();
  const { getLocalizedField } = useLocalizedContent();
  const name = getLocalizedField(item, "name") || item.name;
  const distance = userLat && userLng ? haversineKm(userLat, userLng, item.lat, item.lng) : null;

  return (
    <Card
      className="group cursor-pointer overflow-hidden hover:shadow-lg transition-all duration-300 border-border/50 bg-card"
      onClick={() => navigate(`/restaurant/${item.id}`)}
    >
      <div className="relative aspect-[16/10] overflow-hidden bg-muted">
        {item.image_url ? (
          <img src={item.image_url} alt={name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" loading="lazy" />
        ) : (
          <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-primary/20 to-primary/5">
            <Landmark className="w-12 h-12 text-primary/40" />
          </div>
        )}
      </div>
      <div className="p-3 space-y-1.5">
        <h3 className="font-medium text-sm leading-tight line-clamp-2 text-foreground group-hover:text-primary transition-colors">{name}</h3>
        <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
          <MapPin className="w-3 h-3 flex-shrink-0" />
          <span className="truncate">{item.city || ""}</span>
          {distance != null && (
            <span className="ml-auto shrink-0 text-primary/70 font-medium">{distance.toFixed(1)} km</span>
          )}
        </div>
      </div>
    </Card>
  );
});
LandmarkCard.displayName = "LandmarkCard";

const LoadingSkeleton = memo(() => {
  const count = useResponsiveCount();
  return (
    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
      {Array.from({ length: count }).map((_, i) => (
        <Card key={i} className="overflow-hidden">
          <Skeleton className="aspect-[16/10] w-full" />
          <div className="p-3 space-y-2">
            <Skeleton className="h-4 w-full" />
            <Skeleton className="h-3 w-2/3" />
          </div>
        </Card>
      ))}
    </div>
  );
});
LoadingSkeleton.displayName = "LandmarksSkeleton";

const HomeNearbyLandmarksSection = memo(() => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { lat, lng, isLoading: geoLoading } = useUserGeolocation();
  const [landmarks, setLandmarks] = useState<LandmarkItem[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      try {
        // Use RPC with location if available, otherwise just get recent landmarks
        const { data, error } = await supabase.rpc("get_restaurants_paginated", {
          p_offset: 0,
          p_limit: 8,
          p_search: null,
          p_country: null,
          p_city: null,
          p_district: null,
          p_template: "landmark",
          p_verified: null,
          p_type_filter: null,
          p_activity_id: null,
          p_user_lat: lat ?? null,
          p_user_lng: lng ?? null,
          p_radius_km: lat ? 50 : null,
          p_sort_by_distance: !!lat,
          p_michelin_star: null,
        });

        if (error) throw error;
        const result = data as any;
        setLandmarks((result?.data || []).map((r: any) => ({
          ...r,
          distance: r.distance_km,
        })));
      } catch (err) {
        console.error("[HomeNearbyLandmarks] fetch failed:", err);
      } finally {
        setLoading(false);
      }
    };

    if (!geoLoading) fetch();
  }, [lat, lng, geoLoading]);

  if (!loading && landmarks.length === 0) return null;

  return (
    <section className="py-8 sm:py-12 px-4 bg-secondary/20">
      <div className="container mx-auto max-w-7xl">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl sm:text-2xl font-bold text-foreground">
            {t("home.nearbyLandmarks.title")}
          </h2>
        </div>

        {loading ? <LoadingSkeleton /> : (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
            {landmarks.slice(0, 4).map((item) => (
              <LandmarkCard key={item.id} item={item} userLat={lat} userLng={lng} />
            ))}
          </div>
        )}

        {!loading && landmarks.length > 0 && (
          <div className="flex justify-center mt-6">
            <Button variant="outline" size="lg" className="gap-2" onClick={() => {
              sessionStorage.setItem('restaurants-active-tab', 'landmark');
              navigate("/restaurants");
            }}>
              {t("home.nearbyLandmarks.viewAll")}
              <ArrowRight className="w-4 h-4" />
            </Button>
          </div>
        )}
      </div>
    </section>
  );
});
HomeNearbyLandmarksSection.displayName = "HomeNearbyLandmarksSection";

export default HomeNearbyLandmarksSection;
